using System.Reflection;
var asm = Assembly.LoadFrom(args[0]);
var assertType = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.Assert");
var methods = assertType!.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name is "AreEqual" or "AreNotEqual" or "AreSame")
    .OrderBy(m => m.Name);
foreach (var m in methods)
{
    var genArgs = m.IsGenericMethod ? m.GetGenericArguments() : Array.Empty<Type>();
    var constraints = "";
    foreach (var ga in genArgs)
    {
        var gpc = ga.GenericParameterAttributes;
        constraints += $" where {ga.Name}: {gpc}";
    }
    var ps = string.Join(", ", m.GetParameters().Select(p => {
        var pType = p.ParameterType;
        var typeName = pType.IsGenericType ? $"{pType.Name}<{string.Join(",", pType.GetGenericArguments().Select(a => a.Name))}>" : pType.Name;
        var defaultVal = p.HasDefaultValue ? $" = {p.DefaultValue ?? "null"}" : "";
        var attrs = string.Join(" ", p.GetCustomAttributes().Select(a => $"[{a.GetType().Name}]"));
        return $"{attrs} {typeName} {p.Name}{defaultVal}";
    }));
    var genArgsStr = m.IsGenericMethod ? $"<{string.Join(",", genArgs.Select(a => a.Name))}>" : "";
    Console.WriteLine($"{m.Name}{genArgsStr}({ps}){constraints}");
    Console.WriteLine();
}
EOF
